def max_painted_sections(n: int, painters: List[List[int]]) -> int:
    from functools import lru_cache

    @lru_cache(None)
    def dp(i: int, j: int) -> int:
        if i == len(painters) - 2:
            return sum(painters[i][1] - painters[i][0] + 1 for i in range(len(painters))) - painters[j][1] + painters[j][0] - 1

        max_paint = 0
        for k in range(j + 1, len(painters)):
            max_paint = max(max_paint, dp(i + 1, k))
        return max_paint

    max_paint = 0
    for i in range(len(painters)):
        max_paint = max(max_paint, dp(0, i))
    return max_paint

