def max_painted_sections(n: int, q: int, painters: List[List[int]]) -> int:
    def check_painted(count: int) -> bool:
        painted = [0] * (n + 1)
        painters.sort()
        for i in range(count):
            l, r = painters[i]
            for j in range(l, r + 1):
                painted[j] += 1
        for i in range(1, n):
            painted[i] += painted[i - 1]
        return max(painted) >= n

    l, r = 0, q - 1
    while l < r:
        mid = (l + r + 1) // 2
        if check_painted(mid):
            l = mid
        else:
            r = mid - 1
    return r

