from typing import List

def maximize_painted_sections(n: int, q: int, painters: List[List[int]]) -> int:
    painters.sort(key=lambda x: x[0])
    dp = [[0] * (q - 2) for _ in range(n + 1)]

    for i in range(2, q):
        start, end = painters[i - 2][0], painters[i - 2][1]
        for j in range(start, end + 1):
            dp[j][i - 2] = 1
        for j in range(start - 1, -1, -1):
            dp[j][i - 2] = dp[j + 1][i - 2]
        for j in range(end + 1, n + 1):
            dp[j][i - 2] = dp[j - 1][i - 2]

    for i in range(1, n + 1):
        for j in range(i):
            dp[i][q - 3] += dp[j][q - 4]

    return max(dp[n])

