def can_form_mentsu(hand):
    counts = {'m': {}, 'p': {}, 's': {}}
    for tile in hand:
        counts[tile[1]][tile[0]] = counts[tile[1]].get(tile[0], 0) + 1

    def has_koutsu(suit):
        for num in counts[suit].keys():
            if counts[suit][num] >= 3:
                return True
        return False

    def has_shuntsu(suit):
        numbers = sorted(counts[suit].keys())
        for num in numbers:
            if num + 1 in counts[suit] and num + 2 in counts[suit]:
                return True
        return False

    if has_koutsu('m') or has_koutsu('p') or has_koutsu('s'):
        return 0

    if has_shuntsu('m') or has_shuntsu('p') or has_shuntsu('s'):
        return 0

    for suit in counts:
        for num in counts[suit]:
            for need_num in [str(int(num) - 1), str(int(num) + 1)]:
                if need_num in counts[suit] and has_shuntsu(suit):
                    return 1

    for need in combinations(hand, 2):
        for suit in need:
            for num in counts[suit[1]]:
                if num not in [need[0][0], need[1][0]]:
                    return 1

    return 2

