    cnt = Counter(tiles)
    keys = list(cnt.keys())

    # Check for existing koutsu
    for key in keys:
        if cnt[key] >= 3:
            return 0

    # Check for existing shuntsu
    for i in range(len(keys) - 2):
        if (keys[i][0] == keys[i+1][0] == keys[i+2][0]) and (int(keys[i+1][1]) == int(keys[i][1]) + 1 == int(keys[i+2][1]) - 1):
            return 0

    # Check for koutsu or shuntsu after drawing one tile
    for key in keys:
        cnt[key] -= 1
        if cnt[key] == 2 or (cnt[key] == 1 and any(int(key[1]) == int(other[1]) + 1 == int(next_other[1]) - 1 for other in keys for next_other in keys if other != key and next_other != key and other[0] == next_other[0])):
            return 1
        cnt[key] += 1

    return 2

