def min_tiles_to_draw(hand):
    counter = Counter(hand)
    draws = 0

    for tile in set(hand):
        suit = tile[-1]
        number = int(tile[0])
        needed = []

        # Check for koutsu
        if counter[tile] < 3:
            for num in range(max(1, number - 1), min(9, number + 2)):
                if num == number:
                    continue
                needed.append(f"{num}{suit}")

        # Check for shuntsu
        if len(needed) > 0:
            continue

        for i in range(1, 9):
            sequence = [f"{i}{suit}", f"{i+1}{suit}", f"{i+2}{suit}"]
            if all(counter[num] > 0 for num in sequence):
                draws = max(draws, sequence.count(tile) - 1)
                break

    return draws

