def solve(d: int, n: int, m: int, sofas: List[List[int]], cnt: List[int]) -> int:
    cnt_l, cnt_r, cnt_t, cnt_b = cnt
    pos = [(x1, y1, x2, y2) for x1, y1, x2, y2 in sofas]
    pos.sort(key=lambda x: (x[0], x[1]))

    def check(i: int) -> bool:
        x1, y1, x2, y2 = pos[i]
        cnt_here = [0, 0, 0, 0]  # left, right, top, bottom
        for j in range(d):
            if i != j:
                x3, y3, x4, y4 = pos[j]
                if x1 == x3 == x2 or y1 == y3 == y2:
                    continue
                if x3 < x1 < x4 or x3 < x2 < x4:
                    cnt_here[0] += 1
                if x1 < x3 < x2 or x1 < x4 < x2:
                    cnt_here[1] += 1
                if y3 < y1 < y4 or y3 < y2 < y4:
                    cnt_here[2] += 1
                if y1 < y3 < y2 or y1 < y4 < y2:
                    cnt_here[3] += 1

        return cnt_here == [cnt_l, cnt_r, cnt_t, cnt_b]

    for i in range(d):
        if check(i):
            return i + 1
    return -1

