def max_beauty(trophies):
    n = len(trophies)
    golden_count = trophies.count('G')
    if golden_count == n:
        return n
    start = 0
    end = 0
    max_length = 0
    golden_count_current = 0
    first_silver_index = -1

    while end < n:
        if trophies[end] == 'G':
            golden_count_current += 1
        else:
            if first_silver_index == -1:
                first_silver_index = end
            golden_count_current += 1
        while golden_count_current > golden_count:
            if trophies[start] == 'G':
                golden_count_current -= 1
            start += 1
        max_length = max(max_length, end - start)
        end += 1

    if max_length == n:
        return n - 1

    silver_positions = [i for i, t in enumerate(trophies) if t == 'S']
    if not silver_positions:
        return max_length

    for silver_pos in silver_positions:
        left_g = (silver_pos - start) - (golden_count_current - (silver_pos - start + 1 >= golden_count))
        right_g = (end - silver_pos - 1) - (golden_count - golden_count_current - (silver_pos + 1 >= golden_count))
        max_length = max(max_length, left_g + right_g + 1)

    return max_length

