def stack_sortable(n, k, p):
    if k == n:
        return " ".join(map(str, sorted(p)))

    stack = []
    remaining = set(range(1, n + 1)) - set(p[:k])
    for num in p:
        stack.append(num)
        while stack and stack[-1] == min(remaining):
            remaining.remove(stack[-1])
            stack.pop()

    if not stack or min(stack) != min(remaining):
        return "-1"

    stack.sort(reverse=True)
    remaining = sorted(remaining)
    result = p + [0] * (n - k)

    stack_idx = len(stack) - 1
    for i in range(k, n):
        if stack_idx >= 0 and (stack[stack_idx] in remaining or stack[stack_idx] > remaining[0]):
            result[i] = stack.pop()
            stack_idx -= 1
        else:
            result[i] = remaining.pop(0)

    return " ".join(map(str, result))

