from collections import Counter

def optimal_string(s):
    result = []
    remaining = Counter(s)
    for char in s:
        remaining[char] -= 1
        if all(v == 0 for v in remaining.values()):
            break
        while result and result[-1] < char and remaining[result[-1]] > 0:
            result.pop()
        result.append(char)
    return ''.join(result)

