from collections import deque

def solve(s):
    s = deque(s)
    result = []
    min_suffix = s[-1]

    while s:
        if s[0] <= min_suffix:
            result.append(s.popleft())
            if s:
                min_suffix = min(min_suffix, s[0])
        else:
            temp = s.popleft()
            while result and temp < result[-1]:
                min_suffix = min(min_suffix, result.pop())
            result.append(temp)

    return ''.join(result)

