def min_operations(n, s):
    dp = [0] * (n + 1)
    for i in range(1, n + 1):
        dp[i] = dp[i - 1] + 1
        prefix = s[:i]
        for j in range(i // 2, 0, -1):
            if prefix[:j] == prefix[j:2*j]:
                dp[i] = min(dp[i], dp[j] + i // j - 1)
    return dp[n]

