def min_replacements(ticket):
    from itertools import combinations

    def calculate_replacements(a, b):
        return sum(min(abs(int(x) - int(y)), 10 - abs(int(x) - int(y))) for x, y in zip(a, b))

    mid = 3
    left, right = ticket[:mid], ticket[mid:]
    min_replacement = float('inf')

    for i in range(mid + 1):
        for combo in combinations(range(mid), i):
            new_left = list(left)
            for index in sorted(combo, reverse=True):
                new_left[index] = '0'
            new_left_sum = sum(map(int, new_left))
            for j in range(3):
                if j in combo:
                    new_right_sum = new_left_sum
                    break
                new_right_sum = sum(map(int, right[:j] + [str(new_left_sum - sum(map(int, new_left[:3-j])))] + right[j+1:]))
            min_replacement = min(min_replacement, calculate_replacements(''.join(new_left), right) + abs(i - 3))

    return min_replacement

