def count_common_terms(a1, b1, a2, b2, L, R):
    from math import gcd

    def lcm(x, y):
        return x * y // gcd(x, y)

    common_diff = lcm(a1, a2)
    start = max(L - b1 % common_diff, b2 - b1 + b2)
    end = R - (R % common_diff)

    if start > end:
        return 0

    return (end - start) // common_diff + 1

