def find_position(n):
    if n == 0:
        return (0, 0)

    layer = 0
    while (6 * layer * (layer + 1) // 2) < n:
        layer += 1

    start = 6 * layer * (layer - 1) // 2
    n -= start

    if layer % 4 == 0:
        x, y = -n, 2 * layer - n
    elif layer % 4 == 1:
        x, y = -2 * layer + n, n
    elif layer % 4 == 2:
        x, y = n - 2 * layer, 2 * layer - n
    else:
        x, y = 2 * layer - n, -n

    return (x - (layer - 1) * (layer % 2 == 0), y - (layer - 1) * (layer % 2 != 0))

