def find_position(n):
    if n == 0:
        return 0, 0
    k = 0
    while (3 * k * (k + 1) < n):
        k += 1
    layer_moves = 3 * k * (k + 1)
    remaining_moves = n - (layer_moves - 3 * k * (k - 1))
    delta = remaining_moves - 3 * (k - 1)

    if k % 4 == 0:
        x, y = k - 1 - delta, k - delta
    elif k % 4 == 1:
        x, y = -k + delta, k - 1 - delta
    elif k % 4 == 2:
        x, y = -k + 1 + delta, -k + delta
    elif k % 4 == 3:
        x, y = k - delta, -k + 1 + delta

    x -= (k - 1)
    y -= (k - 1)
    return x, y

