def hex_spiral(n):
    if n == 0:
        return 0, 0
    layer = 0
    while (layer + 1) * 6 <= n:
        layer += 1
    start = layer * 6
    steps = n - start
    x, y = 0, 0
    dx, dy = -1, 0
    for i in range(start, n + 1):
        if i % 4 == 1:
            dx, dy = 0, 1
        elif i % 4 == 2:
            dx, dy = 1, 0
        elif i % 4 == 3:
            dx, dy = 0, -1
        x, y = x + dx, y + dy
        if i % 6 == start % 6:
            break
    return x, y

