def locate_ayrat(n):
    x, y, side = 0, 0, 1
    direction = 0
    while n >= side * 6:
        if direction == 0:
            x -= side
        elif direction == 1:
            y += side
        elif direction == 2:
            x += side
        elif direction == 3:
            y -= side
        elif direction == 4:
            x -= side
        else:
            y -= side
        n -= side * 6
        side += 1
        direction = (direction + 1) % 6
    return x, y

