def find_hexagon_coordinates(n):
    x, y = 0, 0
    level = 0
    while n > 6 * level * (level + 1):
        n -= 6 * level * (level + 1)
        level += 1
    if n <= 3 * level * (level + 1):
        x = (-1) ** (level + 1) * level
        if n <= 2 * level * (level + 1):
            y = level
        else:
            y = -level
            n -= 2 * level * (level + 1)
            x -= 1
    else:
        x = -level
        y = (-1) ** (level + 1) * level
        n -= 3 * level * (level + 1)
        if n <= 2 * level * (level + 1):
            y -= 1
        else:
            x -= 1
            y -= level
            n -= 2 * level * (level + 1)
    return x + (-1) ** level * (n - 1) // (level + 1), y - (-1) ** level * (n - 1) % (level + 1)

