    steps = layer * side * 6
    n -= steps

    if n <= side * 4:
        x = -side + n - 1
        y = 0
    elif n <= side * 5:
        x = 0
        y = side - n + 4
    elif n <= side * 6:
        x = side - (n - side * 5) - 1
        y = side
    else:
        x = 0
        y = -(n - side * 6) + side * 4 - 1
