        return 0, 0

    side = 1
    while side * 6 + 2 <= n:
        side += 1

    moves_left = n - (side * 6 - 6)
    octant = (moves_left - 1) // (side - 1) + 1

    x, y = 0, 0
    directions = [(-2, 0), (-1, -2), (1, -2), (2, 0), (1, 2), (-1, 2), (-2, 0)]

    for i in range(1, side + 1):
        for dir in directions:
            moves = min(side - i + 1, (side - 1) if (i % 2 == 0) else side)
            for _ in range(moves):
                x += dir[0]
                y += dir[1]
                if moves == (side - i + 1) and i == side and octant == 7:
                    return x, y
                if moves == (side - 1) and i == side and octant == 4:
                    return x, y

    return x, y

