        return 0, 0
    layer = int((2 + (8 * n + 1)**0.5) / 4)
    corner = (layer - 1) * 6
    moves_in_layer = (layer - 1) * 12
    x, y = 0, 0
    if n <= corner:
        if layer % 2 == 1:
            x, y = -n + corner, -n + corner
        else:
            x, y = -n + corner, n - corner
    else:
        n -= moves_in_layer
        if layer % 2 == 1:
            x, y = -2, 2
        else:
            x, y = 2, -2
        quarter = (n - 1) // 3
        n -= quarter * 3
        if quarter == 0:
            x += n
            y -= n
        elif quarter == 1:
            x -= n
            y -= n
        elif quarter == 2:
            x -= n
            y += n
        elif quarter == 3:
            x += n
            y += n
    return x, y

