    q, r = divmod(n, 6)
    x, y = 0, 0
    for i in range(q):
        x, y = -y, x
        x += -1 if i % 2 else 1
    if r == 0:
        return x, y
    if r == 1:
        x += 1
    if r == 2:
        x, y = -y, x
        x += 1
    if r == 3:
        x, y = -y, x
        x += 1
        y += 1
    if r == 4:
        y += 1
    if r == 5:
        x, y = -y, x
        y += 1
    return x, y

