def coordinates_after_n_moves(n):
    if n == 0:
        return (0, 0)
    moves = 1
    x, y = 0, 0
    dx, dy = 1, 2
    dir = 0  # 0: right, 1: up-right, 2: up-left, 3: left, 4: down-left, 5: down-right
    while n > moves:
        if dir == 0:  # right
            for _ in range(dx):
                n -= 1
                if n == 0:
                    break
                x += 1
                moves += 1
        elif dir == 1:  # up-right
            for _ in range(dy):
                n -= 1
                if n == 0:
                    break
                y += 1
                moves += 1
        elif dir == 2:  # up-left
            for _ in range(dx):
                n -= 1
                if n == 0:
                    break
                y += 1
                moves += 1
        elif dir == 3:  # left
            for _ in range(dy):
                n -= 1
                if n == 0:
                    break
                x -= 1
                moves += 1
        elif dir == 4:  # down-left
            for _ in range(dx):
                n -= 1
                if n == 0:
                    break
                y -= 1
                moves += 1
        elif dir == 5:  # down-right
            for _ in range(dy):
                n -= 1
                if n == 0:
                    break
                x += 1
                moves += 1
        if dir in [0, 2, 4]:
            dx += 1
        if dir in [1, 3, 5]:
            dy += 1
        dir = (dir + 1) % 6
    return (x, y)

n = int(input())
