def cyclical_strings(n, s):
    from itertools import product

    def rotate(s):
        return s[-1:] + s[:-1]

    if len(s) == n:
        return 1

    ss = set()
    for i in range(len(s)):
        ss.add(s[i:] + s[:i])

    total = 0
    for k in range(n - len(s) + 1):
        for p in product('01', repeat=n - len(s) - k):
            s_ = ss.copy()
            s_.add(s)
            for r in range(n - len(s) - k + 1):
                s_.add(''.join(p[r:n - len(s) - k + r + 1]))
                s_ = {rotate(x) for x in s_}
                if len(s_) >= 2 ** n:
                    total += 1
                    break
    return total

