def count_cyclical_strings(n, s):
    from itertools import permutations

    # Generate all binary strings of length n
    all_strings = [''.join(p) for p in permutations('01', n)]
    valid_strings = set()

    for string in all_strings:
        for i in range(n):
            shifted = string[i:] + string[:i]
            if s in shifted:
                valid_strings.add(shifted)

    return len(valid_strings)

