def cyclical_substrings(n, s):
    mod = 10**9 + 7
    if n < len(s):
        return 0

    z = [0] * len(s)
    l, r = 0, 0
    for i in range(1, len(s)):
        if i <= r:
            z[i] = min(r - i + 1, z[i - l])
        while i + z[i] < len(s) and s[z[i]] == s[i + z[i]]:
            z[i] += 1
        if i + z[i] - 1 > r:
            l, r = i, i + z[i] - 1

    uniq_suffixes = set()
    p = 1
    for i in range(len(s)):
        p = (p << 1) % mod
        if i + z[i] == len(s):
            uniq_suffixes.add(p)
        elif i + z[i] - 1 == len(s) - 1:
            uniq_suffixes.add(p ^ (1 << (len(s) - 1)))

    return (2**(n - len(s)) - len(uniq_suffixes)) % mod

