def count_cyclical_strings(n, s):
    m = len(s)
    if m > n:
        return 0
    # Number of unique cyclical strings containing s
    total = 2 ** (n - m)
    # Subtract the cases where s is not a substring after cyclical shifts
    for i in range(1, m // 2 + 1):
        if s[:i] == s[-i:]:
            total -= 2 ** (n - 2 * i)
    # Add back the over-subtracted cases
    for i in range(1, (m // 2) // 2 + 1):
        if s[:i] == s[-i:] and s[i:2*i] == s[-2*i:-i]:
            total += 2 ** (n - 3 * i)
    return total

