def find_min_angle_vectors(n, vectors):
    sorted_vectors = sorted(enumerate(vectors), key=angle_sort_key)
    min_angle = pi
    min_pair = (0, 0)

    for i in range(n):
        for j in range(i + 1, n):
            angle = abs(degrees(angle_sort_key(sorted_vectors[j][1]) - angle_sort_key(sorted_vectors[i][1])))
