def min_time_to_reach_post_office(d, k, a, b, t):
    if k == 1:
        return d * min(a, b)

    full_trips = d // k
    remaining_distance = d % k

    drive_time = full_trips * k * a
    if remaining_distance > 0:
        drive_time += remaining_distance * a

    repair_time = (full_trips - 1) * t

    walk_time = 0
    if full_trips * k < d:
        walk_time = (d - full_trips * k) * b

    return drive_time + repair_time + walk_time

