def find_sequence(n, k):
    from math import gcd
    from functools import reduce

    def lcm(a, b):
        return a * b // gcd(a, b)

    if k == 1:
        return [n] if n > 0 else [-1]
    elif n < k:
        return [-1]

    max_divisor = reduce(gcd, range(1, k + 1))
    total = (k * (k + 1)) // 2

    if n < total:
        return [-1]

    sequence = [max_divisor * i for i in range(1, k + 1)]
    remaining = n - sum(sequence)

    if remaining == 0:
        return sequence
    elif remaining > 0:
        sequence[-1] += remaining
        return sequence
    else:
        return [-1]

