def find_kth_digit(k):
    if k <= 9:
        return str(k)

    k -= 10

    # Determine the range of numbers where the kth digit falls
    for digits in range(1, 13):
        numbers_in_this_range = 9 * (10 ** (digits - 1))
        if k < digits * numbers_in_this_range:
            break
        k -= digits * numbers_in_this_range

    # Calculate the exact number and digit
    number = 10 ** (digits - 1) + k // digits
    digit_index = k % digits

    return str(number // (10 ** (digits - 1 - digit_index))) % 10

