def max_bourles(n, m, r, buy_prices, sell_prices):
    from functools import lru_cache

    @lru_cache(None)
    def max_profit(remaining_bourles, i):
        if i == len(buy_prices):
            return 0 if remaining_bourles == 0 else -remaining_bourles

        # Buy and then sell
        buy_profit = remaining_bourles // buy_prices[i] * max_profit(buy_prices[i] * (remaining_bourles // buy_prices[i]) - remaining_bourles, i + 1)

        # Skip buying
        skip_profit = max_profit(remaining_bourles, i + 1)

        # Sell
        for j in range(m):
            sell_profit = (remaining_bourles // buy_prices[i]) * sell_prices[j] + max_profit(remaining_bourles % buy_prices[i], i + 1)
            buy_profit = max(buy_profit, sell_profit)

        return max(buy_profit, skip_profit)

    return max_profit(r, 0)

def max_bourles(n, m, r, buy_prices, sell_prices):
    from functools import lru_cache

    @lru_cache(None)
    def dfs(index, budget, shares):
        if index >= len(sell_prices):
            return shares * budget

        buy = 0
        if budget >= min(buy_prices):
            buy = dfs(index + 1, budget - min(buy_prices), shares + budget // min(buy_prices))

        skip = dfs(index + 1, budget, shares)

        sell = 0
        if shares > 0:
            sell = dfs(index + 1, budget + sell_prices[index] * shares, 0)

        return max(buy, skip, sell)

    return dfs(0, r, 0)

