def base_converter(number, base, target_base):
    decimal = 0
    for i, digit in enumerate(reversed(number)):
        decimal += digit * (base ** i)
    return decimal_to_base(decimal, target_base)

def decimal_to_base(decimal, base):
    if decimal == 0:
        return [0]
    digits = []
    while decimal:
        digits.append(int(decimal % base))
        decimal //= base
    return digits[::-1]

