def game_winner(n, nums):
    if n == 1:
        if nums[0] == 0:
            return "BitAryo"
        return "BitLGM"
    min_val = min(nums)
    sum_nums = sum(nums)
    parity = sum_nums % 2
    for num in nums:
        if num - min_val == 0:
            continue
        if (num - (num - min_val)) % 2 == parity:
            return "BitLGM"
    return "BitAryo"

