def solve(n, k, A):
    k_factorization = []
    temp_k = k
    for i in range(2, int(k**0.5) + 1):
        count = 0
        while temp_k % i == 0:
            temp_k //= i
            count += 1
        if count > 0:
            k_factorization.append((i, count))
    if temp_k > 1:
        k_factorization.append((temp_k, 1))

    A = list(accumulate([0] + A, func=lambda x, y: x * y % k, initial=0))

    ways = 0
    for x in range(n):
        for y in range(1, n - x):
            for base, exp in k_factorization:
                if pow(A[x], n - x - y, exp) * pow(A[x] * A[n - y] % k, y, exp) % exp != 0:
                    break
            else:
                ways += 1

    return ways

