from collections import Counter

def count_ways(n, k, deck):
    factors = Counter()
    for num in deck:
        factor = num
        for i in range(2, int(num**0.5) + 1):
            while factor % i == 0:
                factors[i] += 1
                factor //= i
        if factor > 1:
            factors[factor] += 1

    prefix = [0] * (n + 1)
    for i, num in enumerate(deck, 1):
        prefix[i] = prefix[i-1] + (1 if num % k else 0)

    def count_divisible(sub_deck):
        div = 0
        for f, exp in factors.items():
            current_exp = 0
            for i in range(exp, len(sub_deck) + 1, exp):
                current_exp += sub_deck[i-1]
            if current_exp % k == 0:
                div += 1
        return 1 if div > 0 else 0

    result = 0
    for y in range(n):
        sub_deck = prefix[n] - prefix[y+1]
        result += count_divisible(sub_deck)

    return result

