                if operations[i] == 'R': x += 1
                changes += 1
            else:
                if x != 0: 
                    if x < 0: operations[i] = 'R'
                    else: operations[i] = 'L'
                    x += 1
                    changes += 1
                if y != 0: 
                    if y < 0: operations[i] = 'U'
                    else: operations[i] = 'D'
                    y += 1
                    changes += 1
            if x == target[0] and y == target[1]: return changes
        return float('inf')

    start, end = 0, n - 1
    while start <= end:
        mid = (start + end) // 2
        if check(mid, n - mid - 1, target[0], target[1]) != float('inf'):
            return mid + 1
        elif check(n - mid - 1, mid, -target[0], -target[1]) != float('inf'):
            return mid + 1
        elif check(mid, mid, target[0], target[1]) != float('inf'):
            return 0
        if check(mid, n - mid - 1, -target[0], -target[1]) == float('inf'):
            end = mid - 1
        else:
            start = mid + 1
    return -1

