def min_deletions(n, k):
    num_str = str(n)
    len_n = len(num_str)
    count_zeros = 0
    for digit in num_str:
        if digit == '0':
            count_zeros += 1

    if count_zeros >= k:
        return len_n - count_zeros

    zeros_pos = [i for i, digit in enumerate(num_str) if digit == '0']
    suffix_zeros = len_n - zeros_pos[-1] - 1

    if zeros_pos and zeros_pos[0] < k:
        return len_n - zeros_pos[0] - k + suffix_zeros
    else:
        return len_n - 1

