    result = len(n_str)
    suffix_zeros = 0

    for i, digit in enumerate(n_str):
        if digit == '0':
            suffix_zeros += 1
        if i < len(n_str) - k + 1:
            if suffix_zeros >= k:
                result = min(result, i + 1 + (len(n_str) - i - k))
            else:
