def ask_count(k, n, m, x, y):
    full_cycle = n * m
    full_cycles, rest = divmod(k, full_cycle)

    if full_cycles % 2 == 0:
        min_count = (full_cycles // 2) * m
        max_count = min_count + (m - 1 if x <= full_cycles // 2 else 0)
    else:
        min_count = (full_cycles // 2 + 1) * m - m // 2
        max_count = min_count + (m - 1 if x <= full_cycles // 2 + 1 else 0)

    min_count += (rest // n) * m if rest else 0
    if x <= rest % n:
        min_count += (1 if y <= rest % (n * (x - 1)) else 0)
        max_count += (1 if y <= rest % (n * (x - 1)) + m - 1 else 0)
    else:
        min_count += (1 if y <= rest % (n * (x - 1)) + m - 1 else 0)
        max_count += (1 if y <= rest % (n * (x - 1)) else 0)

    return max_count, min_count, (rest // n) * m + (1 if x <= rest % n else 0)

