import math

def count_questions(n, m, k, x, y):
    full_cycle = 2 * n - 2 if n > 1 else 0
    full_cycles = k // full_cycle
    remaining_questions = k % full_cycle

    max_questions = 0
    min_questions = math.ceil(k / (n * m))
    queried = remaining_questions if n > 1 else remaining_questions - 1

    if queried >= x * m - y:
        max_questions = (full_cycles + 1) // 2 + 1
    else:
        max_questions = full_cycles + 1

    if queried < x * m - y + 1:
        queried -= (x - 1) * m
        while queried >= m:
            queried -= m
        queried += 1
        if queried == y:
            queried -= 1
        queried += full_cycles * m
        if x > 1 and queried >= x * m - y:
            queried = x * m - y
        elif x > 1 and queried < x * m - y + 1:
            queried += (x - 1) * m - 1
    else:
        queried = (queried - (x * m - y)) % m
        if queried == 0:
            queried = m

    asked = (full_cycles * (k // n) + queried) // (n * m)

    return max_questions, min_questions, asked

