from collections import Counter, defaultdict

def max_beauty(ribbon, n):
    counts = Counter(ribbon)
    max_freq = max(counts.values())
    freq = defaultdict(list)
    for char, count in counts.items():
        freq[count].append(char)

    if max_freq * 2 <= len(ribbon):
        return max_freq + (n >= len(ribbon) - max_freq)

    if n >= (len(ribbon) - max_freq) * 2 + max_freq - 1:
        return len(ribbon)

    best_char = max(freq[max_freq], key=lambda char: ribbon.count(char))
    n -= len(ribbon) - ribbon.count(best_char)
    return ribbon.count(best_char) + n // (max_freq - 1)

