def chocolateBars(a1, b1, a2, b2):
    def gcd(x, y):
        while y:
            x, y = y, x % y
        return x

    def lcm(x, y):
        return x * y // gcd(x, y)

    total1 = a1 * b1
    total2 = a2 * b2
    goal = (total1 + total2) // 2

    if goal * 2 != total1 + total2:
        return [-1]

    def solve(n, m, target):
        if n * m == target:
            return 0, [(n, m)]
        elif n * m < target:
            return float('inf'), []
        else:
            half1 = solve(n // 2, m, target)
            third1 = solve(n * 2 // 3, m, target)
            half2 = solve(n, m // 2, target)
            third2 = solve(n, m * 2 // 3, target)
            min_steps = min(half1[0], half2[0], third1[0], third2[0]) + 1
            if min_steps == half1[0]:
                return min_steps, half1[1] + [(n // 2, m)]
            elif min_steps == half2[0]:
                return min_steps, half2[1] + [(n, m // 2)]
            elif min_steps == third1[0]:
                return min_steps, third1[1] + [(n * 2 // 3, m)]
            else:
                return min_steps, third2[1] + [(n, m * 2 // 3)]

    min_steps1, sizes1 = solve(a1, b1, goal)
    min_steps2, sizes2 = solve(a2, b2, goal)

    if min_steps1 == float('inf') or min_steps2 == float('inf'):
        return [-1]

    return [min(min_steps1, min_steps2), sizes1[0], sizes2[0]]

