    elif a % 3 == 0:
        return (a // 3, b), (2 * a // 3, b)
    elif b % 2 == 0:
        return (a, b // 2), (a, b // 2)
    elif b % 3 == 0:
        return (a, b // 3), (a, 2 * b // 3)
    return None

