def find_equalization_time(a1, b1, a2, b2):
    from math import gcd

    # Function to calculate the GCD of two numbers
    def gcd(x, y):
        while y:
            x, y = y, x % y
        return x

    # Calculate the area of both bars
    area1 = a1 * b1
    area2 = a2 * b2

    # If areas are already equal, no need to do anything
    if area1 == area2:
        return 0, (a1, b1), (a2, b2)

    # If one area is a factor of the other, no transformation is needed
    if area1 % area2 == 0:
        return 0, (a1, b1), (a2, b2)
    if area2 % area1 == 0:
        return 0, (a1, b1), (a2, b2)

    # Try to equalize the areas
    while True:
        # If one area is a multiple of the other, check if transformation is possible
        if area1 % area2 == 0 or area2 % area1 == 0:
            if area1 % area2 == 0:
                a1, b1 = a1 // (area1 // area2), b1
            else:
                a2, b2 = a2 // (area2 // area1), b2
            return 0, (a1, b1), (a2, b2)

        # Find the maximum possible equalization
        max_equalization = gcd(area1, area2)
        if area1 == area2:
            return 0, (a1, b1), (a2, b2)

        # Decrease the area by the maximum possible amount
        if area1 > area2:
            a1, b1 = a1 // (area1 // max_equalization), b1
            area1 = max_equalization
        else:
            a2, b2 = a2 // (area2 // max_equalization), b2
            area2 = max_equalization

        # Increment the minute count
        time += 1

    return -1, (a1, b1), (a2, b2)

