def count_special_years(a, b):
    def count_in_range(low, high):
        if low > high:
            return 0
        if low == high:
            return 1 if bin(low).count('0') == 1 else 0
        if low & (low + 1) == 0:  # Check if low is of form 2^n
            zeros = bin(low)[3:].count('0')
            ones = bin(low)[3:].count('1')
            if zeros > 0 and ones == 0:
                return (high // low) - (low - 1) // low
            else:
                return 0
        prefix = low - (low & -low)
        suffix = high | -high
        return count_in_range(low, prefix) + count_in_range(prefix + 1, suffix) + count_in_range(suffix + 1, high)

    return count_in_range(a, b)

