def sliding_puzzle(bessie, elsie):
    def get_positions(grid):
        for i in range(2):
            for j in range(2):
                if grid[i][j] == 'X':
                    return (i, j)

    def get_neighbors(position, grid):
        x, y = position
        neighbors = []
        if x > 0:
            neighbors.append(((x-1, y), grid[x-1][y] + grid[x][y] + grid[x][y+1], swap(grid, (x, y), (x-1, y))))
        if x < 1:
            neighbors.append(((x+1, y), grid[x+1][y] + grid[x][y] + grid[x][y+1], swap(grid, (x, y), (x+1, y))))
        if y > 0:
            neighbors.append(((x, y-1), grid[x][y-1] + grid[x][y] + grid[x+1][y], swap(grid, (x, y), (x, y-1))))
        if y < 1:
            neighbors.append(((x, y+1), grid[x][y+1] + grid[x][y] + grid[x+1][y], swap(grid, (x, y), (x, y+1))))
        return neighbors

    def swap(grid, p1, p2):
        new_grid = [list(row) for row in grid]
        new_grid[p1[0]][p1[1]], new_grid[p2[0]][p2[1]] = new_grid[p2[0]][p2[1]], new_grid[p1[0]][p1[1]]
        return tuple(map(tuple, new_grid))

    def bfs(initial_bessie, initial_elsie):
        visited = set()
        queue_bessie = deque([(initial_bessie, 0)])
        queue_elsie = deque([(initial_elsie, 0)])
        while queue_bessie and queue_elsie:
            if queue_bessie[0][0] == queue_elsie[0][0]:
                return "YES"
            bessie_state, bessie_steps = queue_bessie.popleft()
            elsie_state, elsie_steps = queue_elsie.popleft()
            if bessie_state in visited or elsie_state in visited:
                continue
            visited.add(bessie_state)
            visited.add(elsie_state)
            for neighbor_bessie in get_neighbors(get_positions(bessie_state), bessie_state):
                if neighbor_bessie[1] not in [state[1] for state in visited]:
                    queue_bessie.append((neighbor_bessie[2], bessie_steps + 1))
            for neighbor_elsie in get_neighbors(get_positions(elsie_state), elsie_state):
                if neighbor_elsie[1] not in [state[1] for state in visited]:
                    queue_elsie.append((neighbor_elsie[2], elsie_steps + 1))
        return "NO"

    initial_bessie = tuple(bessie)
    initial_elsie = tuple(elsie)
    return bfs(initial_bessie, initial_elsie)

