def slide(grid, dir):
    x, y = 0, 0
    for i in range(2):
        for j in range(2):
            if grid[i][j] == 'X':
                x, y = i, j
                break
    nx, ny = x, y
    if dir == 'U': nx -= 1
    if dir == 'D': nx += 1
    if dir == 'L': ny -= 1
    if dir == 'R': ny += 1
    if 0 <= nx < 2 and 0 <= ny < 2:
        new_grid = [list(row) for row in grid]
        new_grid[x][y], new_grid[nx][ny] = new_grid[nx][ny], 'X'
        return ''.join([''.join(row) for row in new_grid])
    return None

def bfs(start, target):
    visited = set()
    queue = deque([(start, 0)])
    while queue:
        grid, moves = queue.popleft()
        if grid == target:
            return True
        if grid in visited:
            continue
        visited.add(grid)
        for d in 'UDLR':
            new_grid = slide(grid, d)
            if new_grid and new_grid not in visited:
                queue.append((new_grid, moves + 1))
    return False

