        for i in range(2):
            for j in range(2):
                if grid[i][j] == 'X':
                    return i, j

    def slide(grid, empty_i, empty_j, direction):
        i, j = empty_i, empty_j
        if direction == 'up':
            grid[i][j], grid[i + 1][j] = grid[i + 1][j], grid[i][j]
            return grid, (i + 1, j)
        elif direction == 'down':
            grid[i][j], grid[i - 1][j] = grid[i - 1][j], grid[i][j]
            return grid, (i - 1, j)
        elif direction == 'left':
            grid[i][j], grid[i][j + 1] = grid[i][j + 1], grid[i][j]
            return grid, (i, j + 1)
        elif direction == 'right':
            grid[i][j], grid[i][j - 1] = grid[i][j - 1], grid[i][j]
            return grid, (i, j - 1)

    def solve(puzzle):
        visited = set()
        queue = [(puzzle, 0, 0)]
        while queue:
            current, moves, empty_i, empty_j = queue.pop(0)
