def sliding_puzzle_isomorphic(puzzle1, puzzle2):
    def get_position(grid, char):
        for i in range(2):
            for j in range(2):
                if grid[i][j] == char:
                    return i, j

    def slide(grid, direction):
        for i in range(2):
            for j in range(2):
                if grid[i][j] == 'X':
                    if direction == 'U' and i > 0:
                        grid[i][j], grid[i-1][j] = grid[i-1][j], grid[i][j]
                    elif direction == 'D' and i < 1:
                        grid[i][j], grid[i+1][j] = grid[i+1][j], grid[i][j]
                    elif direction == 'L' and j > 0:
                        grid[i][j], grid[i][j-1] = grid[i][j-1], grid[i][j]
                    elif direction == 'R' and j < 1:
                        grid[i][j], grid[i][j+1] = grid[i][j+1], grid[i][j]
                    return

    def isomorphic(puzzle1, puzzle2):
        for _ in range(4):  # Rotate puzzle1 4 times
            for _ in range(2):  # Flip puzzle1 horizontally and check
                for i in range(2):
                    puzzle1[i] = puzzle1[i][::-1]
                for _ in range(4):  # Rotate again
                    puzzle1_rotated = [list(row) for row in zip(*puzzle1[::-1])]
                    if puzzle1_rotated == puzzle2:
                        return True
                    slide(puzzle1_rotated, 'D')
            slide(puzzle1, 'R')
        return False

    for i in range(2):
        puzzle1[i] = list(puzzle1[i])
        puzzle2[i] = list(puzzle2[i])

    for char in 'ABC':
        x1, y1 = get_position(puzzle1, char)
        x2, y2 = get_position(puzzle2, char)
        if abs(x1 - x2) + abs(y1 - y2) > 1:
            return 'NO'

    if isomorphic(puzzle1, puzzle2):
        return 'YES'
    else:
        return 'NO'

