    elif vx == vy:
        if (n + m - x - y) % (2 * n + 2 * m) == 0:
            return -1, -1
    elif vx == -vy:
        if (x + y) % (2 * n + 2 * m) == 0:
            return -1, -1
    elif vx == 1 and vy == -1:
        t = (n - x) / (x + y)
        if t.is_integer() and (n + m - x - y) % (2 * n + 2 * m) == 0:
            return -1, -1
        t = int(t)
        x, y = n - x, y + t
        while x >= n or y >= m:
            if x >= n:
                x -= n
            if y >= m:
                y -= m
        return x, y
    elif vx == -1 and vy == 1:
        t = (m - y) / (x + y)
        if t.is_integer() and (n + m - x - y) % (2 * n + 2 * m) == 0:
            return -1, -1
        t = int(t)
        x, y = x + t, m - y
        while x >= n or y >= m:
            if x >= n:
                x -= n
            if y >= m:
                y -= m
        return x, y
    return -1, -1

