        if x == 0 or x == n or y == 0 or y == m:
            return (x, y)

        if vx == 1 and vy == 1:
            x = n - x
            y = m - y
            vx = -1
            vy = -1
        elif vx == -1 and vy == -1:
            x = x + n
            y = y + m
            vx = 1
            vy = 1
        elif vx == 1 and vy == 0:
            x = n - x
            vx = -1
        elif vx == -1 and vy == 0:
            x = x + n
            vx = 1
        elif vy == 1 and vx == 0:
            y = m - y
            vy = -1
        elif vy == -1 and vx == 0:
            y = y + m
            vy = 1
        else:
            x = x + n if vx == 1 else x - n
            y = y + m if vy == 1 else y - m

            if vx == 1:
                x = n - x
            elif vx == -1:
                x = x + n
            if vy == 1:
                y = m - y
            elif vy == -1:
                y = y + m
            vx, vy = vy, vx

        if x < 0 or x > n or y < 0 or y > m:
            return -1

