def ball_fall(n, m, x, y, vx, vy):
    if vx == 0:
        if vy == 1:
            return n, m
        elif vy == -1:
            return 0, 0
        else:
            return -1
    if vy == 0:
        if vx == 1:
            return n, y
        elif vx == -1:
            return x, 0
        else:
            return -1

    cycles_x = (n - x) // (2 * abs(vx))
    cycles_y = (m - y) // (2 * abs(vy))

    if cycles_x == cycles_y:
        if cycles_x > 0:
            if vx == 1 and vy == 1:
                return n, m
            elif vx == -1 and vy == -1:
                return 0, 0
        return -1

    if cycles_x < cycles_y:
        if vx == 1:
            return n, y + (cycles_x * 2 * vy)
        elif vx == -1:
            return x - (cycles_x * 2 * vy), 0
        else:
            return -1

    if vy == 1:
        return x + (cycles_y * 2 * vx), m
    elif vy == -1:
        return 0, y - (cycles_y * 2 * vx)
    else:
        return -1

