            top = min(top, row)
            bottom = max(bottom, row)

    for col in range(m):
        if any(grid[row][col] == 'w' for row in range(n)):
            left = min(left, col)
            right = max(right, col)

    width = right - left + 1
    height = bottom - top + 1

    if width > 2 and height > 2:
        for row in range(top, bottom + 1):
            for col in range(left, right + 1):
                if col == left or col == right or row == top or row == bottom:
                    grid[row][col] = '+'
                else:
                    grid[row][col] = 'w'
    elif width == 2 and height == 2:
        for row in range(top, bottom + 1):
            for col in range(left, right + 1):
                grid[row][col] = '+'
    elif width == 2:
        for row in range(top, bottom + 1):
            grid[row][left] = '+'
            grid[row][right] = '+'
            grid[top][right] = '+'
            if row != top:
                grid[row][right - 1] = 'w'
            if row != bottom:
                grid[row][right + 1] = 'w'
            if row != bottom - 1 and row != top + 1:
                grid[top + 1][right - 1] = 'w'
    elif height == 2:
        for col in range(left, right + 1):
            grid[top][col] = '+'
            grid[bottom][col] = '+'
            grid[bottom][left] = '+'
            if col != left:
