def min_time_to_reach(n, m, k, a, b):
    def dist(x, y):
        return min(abs(x - y), n * m * k - abs(x - y))

    def time(delta):
        if delta % (n * m) == 0:
            return 15 * n * m // (n * m) + (delta // (n * m)) * 15
        else:
            return 10 + 1 + (delta // m) * 5

    a_idx, b_idx = (a - 1) // (m * k), (b - 1) // (m * k)
    a_mod, b_mod = (a - 1) % (m * k) + 1, (b - 1) % (m * k) + 1

    if a_mod == b_mod:
        return time(dist(a_idx, b_idx))
    else:
        min_t = float('inf')
        for i in range(n):
            up = dist(a_idx, (i * m * k + b_mod - 1) // (m * k)) + time((i * m * k + b_mod - 1) % (m * k) - a_mod)
            down = dist(a_idx, ((i + 1) * m * k - b_mod) // (m * k)) + time((a_mod - (i + 1) * m * k + b_mod) % (m * k) + m * k)
            min_t = min(min_t, up, down)
        return min_t

