def min_time_to_reach_target(n, m, k, a, b):
    a_index, b_index = (a - 1) // k, (b - 1) // k
    a_floor, b_floor = (a - 1) % k, (b - 1) % k
    a_building, b_building = a_index // m, b_index // m
    a_shift, b_shift = a_index % m, b_index % m

    def distance_in_building(start, end):
        return abs(end - start)

    def distance_between_buildings(s_b, e_b):
        return abs((s_b - e_b) % n)

    def min_time_for_floor(distance, in_building):
        return min(15 + 5 * distance, 10 + 1 * distance + 15)

    def overall_time(a_b, a_f, b_b, b_f):
        horizontal = distance_between_buildings(a_b, b_b) * 15
        vertical_a = min_time_for_floor(a_f, in_building=True)
        vertical_b = min_time_for_floor(b_f, in_building=True)
        return horizontal + vertical_a + vertical_b

    vertical_a = min_time_for_floor(a_floor, in_building=False)
    vertical_b = min_time_for_floor(b_floor, in_building=False)
    same_building = overall_time(a_building, a_floor, b_building, b_floor)
    different_building = overall_time(a_building, a_floor, a_building + 1, b_floor) + min_time_for_floor(b_floor, in_building=True)
    different_building_opposite = overall_time(a_building, a_floor, a_building - 1, b_floor) + min_time_for_floor(b_floor, in_building=True)

    return min(same_building, different_building, different_building_opposite)

