        if b_ != b__:
            dist += min(abs(b_ - b__), abs(m * k - abs(b_ - b__))) * 10 + abs(a_ - a__) + abs(a_ - a__)
        dist += abs(b_ - b__) * 5
        return dist

    af, an, au = get_floor_and_unit(a, a)
