def min_time_to_reach(n, m, k, a, b):
    total_units = n * m * k
    a -= 1
    b -= 1

    def distance(p1, p2):
        return min(abs(p1 - p2), total_units - abs(p1 - p2))

    def subproblem(p1, p2):
        if p1 == 0 and p2 < k:
            return min(15, 5 * (k - p2))
        elif p2 == 0 and p1 < k:
            return min(15, 5 * (k - p1))
        elif p1 == 0 or p2 == 0:
            return 5 * abs(p1 - p2)
        else:
            return min(1 + subproblem(p1 - 1, p2 - 1), 1 + subproblem(p1 - 1, p2), 1 + subproblem(p1, p2 - 1))

    def path_planning(n1, m1, n2, m2):
        if n1 == n2:
            return 15 * abs(m1 - m2)
        else:
            circle = abs(n1 - n2)
            inside = min(abs(m1 - m2), m - abs(m1 - m2))
            return 10 + 15 * (circle - 1) + 5 * (circle - 1) + inside

    in_same_subproblem = (a // k) == (b // k)
    if in_same_subproblem:
        return subproblem(a % k, b % k)
    else:
        sub1 = min(a % k, k - a % k)
        sub2 = min(b % k, k - b % k)
        n1, m1 = a // k, a % k
        n2, m2 = b // k, b % k
        circle = abs(n1 - n2)
        return 10 + min(path_planning(n1, m1, n2, m2), circle * 15 + sub1 + sub2)

