        ap, ay, ah = divmod(x, k)
        bp, by, bh = divmod(y, k)
        at = abs(ap - bp) * 15 + min(ah * 5 + (m - bh) * 5, (m - ah) * 5 + bh * 5)
        bt = abs(ay - by) * 5
        return at + bt

    def wrap_time(t):
        return min(t, 10 + t % 10)

    def dp(x):
        nonlocal a, b
        a -= x
        b -= x
        return min(wrap_time(calculate_time(a, b)), wrap_time(calculate_time(b, a)))

    return dp(0)

