def probability_of_survival(r, s, p):
    total = r + s + p
    if r == 0:
        return 0, (s/p) / (1 + (s/p)), (p/s) / (1 + (p/s))
    if s == 0:
        return (r/p) / (1 + (r/p)), 0, (p/r) / (1 + (p/r))
    if p == 0:
        return (s/r) / (1 + (s/r)), (r/s) / (1 + (r/s)), 0
    a, b, c = r / total, s / total, p / total
    p_r = (1 - a * b - b * c - c * a) / (2 - 2 * a)
    p_s = (1 - a * b - b * c - c * a) / (2 - 2 * b)
    p_p = (1 - a * b - b * c - c * a) / (2 - 2 * c)
    return p_r, p_s, p_p

