def decode_genome(n, s):
    from collections import Counter

    # Count the occurrences of each nucleotide
    counts = Counter(s)
    total = counts['?'] + counts['A'] + counts['C'] + counts['G'] + counts['T']
    if total % 4 != 0:
        return "==="

    avg_count = total // 4
    for nucleotide in 'ACGT':
        if counts[nucleotide] > avg_count:
            return "==="

    # Calculate the number of each nucleotide needed
    needed = {nucleotide: avg_count - counts[nucleotide] for nucleotide in 'ACGT'}

    # Replace '?' with the needed nucleotides
    for nucleotide, need in needed.items():
        for _ in range(need):
            s = s.replace('?', nucleotide, 1)

    return s

