def decode_genome(n, s):
    from collections import Counter
    unknowns = s.count('?')
    needed = n // 4
    if unknowns > needed:
        return "==="

    counts = Counter(s.replace('?', ''))
    excess = {nucleotide: needed - count for nucleotide, count in counts.items() if count < needed}
    if sum(excess.values()) > unknowns:
        return "==="

    remaining_unknowns = unknowns - sum(excess.values())
    order = ['A', 'C', 'G', 'T']
    for nucleotide in order:
        if nucleotide not in counts:
            counts[nucleotide] = 0

    for nucleotide in order:
        if excess.get(nucleotide, 0) > 0:
            to_add = excess[nucleotide]
            while to_add > 0:
                for i in range(n):
                    if s[i] == '?' and remaining_unknowns > 0:
                        s = s[:i] + nucleotide + s[i+1:]
                        remaining_unknowns -= 1
                        to_add -= 1
                        if to_add <= 0:
                            break
        elif counts[nucleotide] < needed:
            to_add = needed - counts[nucleotide]
            while to_add > 0:
                for i in range(n):
                    if s[i] == '?' and remaining_unknowns > 0:
                        s = s[:i] + nucleotide + s[i+1:]
                        remaining_unknowns -= 1
                        to_add -= 1
                        if to_add <= 0:
                            break

    return s

