    from collections import Counter
    import string

    nucleotides = 'ACGT'
    nucleotide_counts = Counter(s)
    question_marks = s.count('?')

    if question_marks % (4 - (n - question_marks)) != 0:
        return "==="

    for nucleotide in nucleotides:
        needed = (n - question_marks) // 4
        if nucleotide_counts[nucleotide] + question_marks < 4 * needed:
            return "==="

    def fill_nucleotides():
        nucleotide_counts = Counter(s)
        for i, char in enumerate(s):
            if char == '?':
                for nucleotide in nucleotides:
                    if nucleotide_counts[nucleotide] < (n - question_marks) // 4:
                        s = s[:i] + nucleotide + s[i+1:]
                        nucleotide_counts[nucleotide] += 1
                        break

    fill_nucleotides()
    return s

