def decode_genome(n, s):
    from collections import Counter
    nucleotides = {'A', 'C', 'G', 'T'}
    unknown_count = s.count('?')
    if unknown_count > n - unknown_count:
        return '==='

    remaining_slots = n - unknown_count
    target_count = remaining_slots // 4
    for nucleotide in nucleotides:
        if s.count(nucleotide) < target_count:
            return '==='

    replacement = {nucleotide: n // 4 for nucleotide, n in Counter(s).items()}
    for nucleotide in nucleotides:
        if s.count(nucleotide) < target_count:
            replacement[nucleotide] = target_count - s.count(nucleotide)

    decoded = []
    for char in s:
        if char == '?':
            for nucleotide in nucleotides:
                if replacement[nucleotide] > 0:
                    decoded.append(nucleotide)
                    replacement[nucleotide] -= 1
                    break
        else:
            decoded.append(char)

    return ''.join(decoded)

