def decode_genome(n, genome):
    from collections import Counter

    if n % 4 != 0:
        return "==="

    count = Counter(genome)
    total = n // 4

    for nucleotide in ['A', 'C', 'G', 'T']:
        if count[nucleotide] > total:
            return "==="

    missing = total - count['A']
    missing -= total - count['C']
    missing -= total - count['G']
    missing -= total - count['T']

    result = []
    for char in genome:
        if char == '?':
            for nucleotide in ['A', 'C', 'G', 'T']:
                if missing > 0 and count[nucleotide] < total:
                    result.append(nucleotide)
                    missing -= 1
                    count[nucleotide] += 1
                else:
                    result.append(char)
        else:
            result.append(char)

    return ''.join(result)

