    from collections import Counter

    unknown = s.count('?')
    counts = Counter(s.replace('?', ''))

    if len(counts) > 1 or unknown % 4 != 0:
        return '==='

    new_counts = {k: (n // 4 + (1 if i < unknown % n else 0)) for i, k in enumerate('ACGT')}
    res = []
    for char in s:
        if char == '?':
            for k in 'ACGT':
                if new_counts[k] > 0:
                    res.append(k)
                    new_counts[k] -= 1
                    break
        else:
            res.append(char)

    return ''.join(res)

