def decode_genome(n, genome):
    from collections import Counter
    from math import ceil

    unknown = genome.count('?')
    total = 4 * (n // 4)
    if unknown > total - n:
        return "==="

    count = Counter(genome.replace('?', ''))
    needed = {k: max(0, ceil((total - n) / 4) - v) for k, v in count.items()}

    for i in range(n):
        if genome[i] == '?':
            for k in 'ACGT':
                if needed[k] > 0:
                    genome = genome[:i] + k + genome[i+1:]
                    needed[k] -= 1
                    break

    return genome

