def decode_genome(n, s):
    from collections import Counter
    import math

    count = Counter(s)
    total = n
    if total % 4 != 0:
        return "==="

    target = total // 4
    needs = {k: target - v for k, v in count.items() if k != '?'}
    if any(v < 0 for v in needs.values()):
        return "==="

    ans = list(s)
    i = 0
    for k, v in sorted(needs.items(), key=lambda x: (x[1], x[0])):
        while v > 0 and i < total:
            if ans[i] == '?':
                ans[i] = k
                v -= 1
            i += 1
    return ''.join(ans)

