def max_products(n, f, days):
    events = []
    for k, l in days:
        events.append((l, k, 0))  # normal day
        if k < l:
            events.append((l, k * 2, 1))  # sell-out day

    events.sort(reverse=True)

    max_sold = 0
    total_products = 0
    for l, k, is_sellout in events:
        if f > 0 and is_sellout:
            max_sold += min(k, l)
        else:
            max_sold += min(total_products, l)
        total_products += k
        if f > 0:
            f -= 1

    return max_sold

