def min_coins(N, M, K, L):
    if M * N < K + L:
        return -1
    if M == 1:
        return -1 if K + L > N else N - K
    x = (K + L) // M
    y = (K + L) % M
    if x + 1 <= N:
        return x + (1 if y > 0 else 0)
    elif x + M <= N:
        return x + 1
    else:
        return -1

