def dp(n, p, colors):
    if n == 1:
        if p == 0:
            return 0 if colors[0] == -1 else 1
        else:
            return 1 if colors[0] == -1 else 0
    dp = [[0, 0] for _ in range(n)]
    if colors[0] == 0:
        dp[0][0] = 1
    elif colors[0] == 1:
        dp[0][1] = 1
    if colors[-1] == 1:
        dp[-1][1] = 1
    elif colors[-1] == 0:
        dp[-1][0] = 1
    for i in range(1, n-1):
        if colors[i] == -1:
            for j in range(2):
                dp[i][j] = (dp[i-1][1-j] + dp[i-1][j]) % mod
        elif colors[i] == 0:
            dp[i][0] = (dp[i-1][1] + dp[i-1][0]) % mod
        else:
            dp[i][1] = (dp[i-1][0] + dp[i-1][1]) % mod
    if colors[-1] == -1:
        return (dp[-2][0] + dp[-2][1]) % mod
    elif colors[-1] == 0:
        return dp[-2][1]
    else:
        return dp[-2][0]

