    dp[0] = 1

    for mask in range(1 << n):
        current_color = 0
        has_black = False
        has_white = False

        for i in range(n):
            if mask & (1 << i):
                if colors[i] == 0:
                    has_black = True
                elif colors[i] == 1:
                    has_white = True
                else:
                    current_color = 1 - current_color

        if (has_black and not has_white) or (has_white and not has_black):
            continue

        for i in range(n):
            if not mask & (1 << i):
                next_mask = mask | (1 << i)
                if current_color == 1:
                    dp[next_mask] = (dp[next_mask] + dp[mask]) % mod
                else:
                    dp[next_mask] = (dp[next_mask] + dp[mask] * 2) % mod

    return sum(dp) * (1 + int(p)) // 2 % mod

