def count_ways(n, p, colors):
    MOD = 10**9 + 7
    painted = [False] * n
    count = [0] * n
    graph = defaultdict(list)
    for i in range(n):
        if colors[i] != -1:
            painted[i] = True
            count[colors[i]] += 1
    for i in range(n):
        if not painted[i]:
            for j in range(n):
                if painted[j] and colors[i] != colors[j]:
                    graph[i].append(j)
                    graph[j].append(i)

    def dfs(node, color, par):
        if colors[node] == -1:
            colors[node] = color
            count[color] += 1
        for nei in graph[node]:
            if nei == par:
                continue
            if colors[nei] == -1:
                dfs(nei, 1 - color, node)
            elif colors[nei] == colors[node]:
                return False
        return True

    total_ways = 0
    for i in range(n):
        if not painted[i]:
            colors = [-1] * n
            if not dfs(i, 0, -1):
                break
            ways = 1
            for color in [0, 1]:
                if count[color] % 2 != 0:
                    ways = (ways * pow(2, count[color], MOD)) % MOD
            if (count[0] + count[1]) % 2 == p:
                total_ways = (total_ways + ways) % MOD
    return total_ways

