def count_ways(n, p, colors):
    from functools import cache

    @cache
    def dfs(u, color):
        if u == n:
            return 1
        ways = 0
        if colors[u] == -1:
            for nc in (0, 1):
                ways += dfs(u + 1, nc)
                ways %= mod
        else:
            nc = colors[u]
            for v in range(u + 1, n):
                if colors[v] == -1 or (colors[v] != -1 and (colors[v] == nc and (v - u) % 2 == 0) or (colors[v] != nc and (v - u) % 2 != 0)):
                    ways += dfs(v, -1)
                    ways %= mod
        return ways

    total_ways = 0
    for start_color in (0, 1):
        total_ways += dfs(0, start_color)
        total_ways %= mod

    return total_ways if p == 1 else (2**n - total_ways) % mod

