def calculate_ways(n, p, colors):
    MOD = 10**9 + 7
    dp = [0] * (1 << n)
    dp[0] = 1
    for mask in range(1 << n):
        for i in range(n):
            if not mask & (1 << i):
                new_mask = mask | (1 << i)
                if i == 0 or (colors[i-1] != -1 and (colors[i-1] != colors[i] or (colors[i-1] == -1 and (new_mask & (1 << (i-1))) == 0))):
                    dp[new_mask] += dp[mask]
                    dp[new_mask] %= MOD

    count_black, count_white = 0, 0
    for mask in range(1 << n):
        if dp[mask] % 2 == p:
            for i in range(n):
                if mask & (1 << i):
                    if colors[i] == -1:
                        if i == 0 or (colors[i-1] != -1 and (colors[i-1] != colors[i] or (colors[i-1] == -1 and (mask & (1 << (i-1))) == 0))):
                            count_black += 1
                    else:
                        count_white += 1

    ways = pow(2, count_black, MOD) * pow(2, count_white, MOD) % MOD
    return ways

