def max_good_subset_weight(W, cnt):
    weights = [1, 2, 3, 4, 5, 6, 7, 8]
    dp = [0] * (W + 1)

    for i in range(8):
        for j in range(W, -1, -1):
            for k in range(cnt[i] + 1):
                if j - weights[i] * k >= 0:
                    dp[j] = max(dp[j], dp[j - weights[i] * k] + weights[i] * k)

    return dp[W]

