def max_good_subset_weight(W, cnt):
    max_weight = 0
    for weights in product(range(9), repeat=8):
        total_weight = sum(i * w for i, w in zip(range(9), weights))
        if total_weight <= W:
            max_weight = max(max_weight, sum(i * w for i, w in zip(range(9), weights) if w <= cnt[i]))
    return max_weight

