def max_diff(n, k, tabs):
    def simulate(b):
        closed = set()
        i = 1
        while True:
            c = b + (i - 1) * k
            if 1 <= c <= n:
                closed.add(c)
            else:
                break
            i += 1

        e = sum(1 for i in range(1, n+1) if i not in closed and tabs[i-1] == 1)
        s = sum(1 for i in range(1, n+1) if i not in closed and tabs[i-1] == -1)
        return abs(e - s)

    return max(simulate(i) for i in range(1, n+1))

