def min_cost_alphabet(n, c0, c1):
    if c0 == 0:
        return n * c1
    if c1 == 0:
        return n * c0
    total_cost = 0
    smaller, bigger = (c0, c1) if c0 < c1 else (c1, c0)
    while n > 0:
        if n % 2 == 1:
            total_cost += smaller
        n //= 2
        smaller, bigger = bigger, smaller + bigger
    return total_cost

