def make_coprime(arr):
    n = len(arr)
    additions = 0
    modified_arr = []

    for i, (a, b) in enumerate(pairwise(arr)):
        if gcd(a, b) != 1:
            additions += 1
            modified_arr.append(1)
        modified_arr.append(a)

    if n == 1:
        return 0, arr[0]
    elif additions == 0:
        return 0, arr
    else:
        modified_arr.append(arr[-1])
        return additions, modified_arr

