def solve(a, b):
    if not any(ch in a for ch in b):
        return '-'

    def find_start(b, a):
        start = 0
        for ch in b:
            start = a.find(ch, start) + 1
            if start == 0:
                return -1
        return start

    def find_end(b, a):
        end = len(a)
        for ch in reversed(b):
            end = a.rfind(ch, 0, end)
            if end == len(a):
                return -1
        return end

    start = find_start(b, a)
    if start == -1:
        return '-'

    end = find_end(b, a)
    if end == -1:
        return '-'

    return a[start-1:end]

