def is可达(path, street):
    n, m = len(path), len(street)
    visited = [[False] * m for _ in range(n)]

    def dfs(x, y):
        if x < 0 or x >= n or y < 0 or y >= m or visited[x][y]:
            return
        visited[x][y] = True
        if path[x] == '<':
            dfs(x, y-1)
        else:
            dfs(x, y+1)
        if street[y] == 'v':
            dfs(x+1, y)
        else:
            dfs(x-1, y)

    dfs(0, 0)
    return all(visited[i][j] for i in range(n) for j in range(m))

