def check_traffic_flow(n, m, horiz_streets, vert_streets):
    # Create a grid to represent the city
    city = [[''] * m for _ in range(n)]

    # Fill the grid with directions
    for i in range(n):
        for j in range(m):
            if horiz_streets[i] == '>':
                city[i][j] = 'E'  # East to West
            else:
                city[i][j] = 'W'  # West to East

    for j in range(m):
        for i in range(n):
            if vert_streets[j] == '^':
                city[i][j] = 'S' if city[i][j] == 'E' else 'N'
            else:
                city[i][j] = 'N' if city[i][j] == 'E' else 'S'

    # Check if the grid is connected
    def dfs(x, y, visited):
        if visited[x][y]:
            return
        visited[x][y] = True
        for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            nx, ny = x + dx, y + dy
            if 0 <= nx < n and 0 <= ny < m and city[x][y] == city[nx][ny]:
                dfs(nx, ny, visited)

    visited = [[False] * m for _ in range(n)]
    dfs(0, 0, visited)
    return all(all(row) for row in visited)

