def is_reachable(n, m, horiz, vert):
    # Create a graph representation
    graph = [[0] * m for _ in range(n)]

    # Build the graph
    for i in range(n):
        for j in range(m):
            if horiz[i] == '<':
                graph[i][j] += (1 if j > 0 else 0)
            else:
                graph[i][j] += (1 if j < m - 1 else 0)
            if vert[j] == '^':
                graph[i][j] += (1 if i > 0 else 0)
            else:
                graph[i][j] += (1 if i < n - 1 else 0)

    # Check for connectivity
    visited = [False] * (n * m)

    def dfs(x, y):
        if visited[x * m + y]:
            return
        visited[x * m + y] = True
        for dx, dy in [(0, 1), (1, 0), (0, -1), (-1, 0)]:
            nx, ny = x + dx, y + dy
            if 0 <= nx < n and 0 <= ny < m and graph[nx][ny]:
                dfs(nx, ny)

    dfs(0, 0)

    return all(visited)

