def is_reachable(n, m, horiz_dirs, vert_dirs):
    # Create a graph representing the grid
    graph = [[0] * m for _ in range(n)]

    # Populate the graph with directions
    for i in range(n):
        for j in range(m):
            if horiz_dirs[i] == '>':
                graph[i][j] = 1  # East to West
            else:
                graph[i][j] = -1  # West to East

    for j in range(m):
        for i in range(n):
            if vert_dirs[j] == '^':
                graph[i][j] += 2  # South to North
            else:
                graph[i][j] -= 2  # North to South

    # Check connectivity
    visited = set()
    stack = [(0, 0)]
    while stack:
        i, j = stack.pop()
        if (i, j) in visited:
            continue
        visited.add((i, j))
        if i > 0:
            stack.append((i-1, j))
        if i < n-1:
            stack.append((i+1, j))
        if j > 0:
            stack.append((i, j-1))
        if j < m-1:
            stack.append((i, j+1))

    return len(visited) == n * m

