def solve_stick_lengths():
    n = int(input().strip())
    lengths = list(map(int, input().strip().split()))

    # Calculate the frequency of each length
    freq = [0] * 101
    for length in lengths:
        freq[length] += 1

    # Find the most frequent length
    max_freq = 0
    for i in range(1, 101):
        if freq[i] > freq[max_freq]:
            max_freq = i

    # Calculate the total cost for each possible t
    total_cost = []
    for t in range(1, 101):
        cost = 0
        for i in range(1, 101):
            if i == t:
                continue
            cost += freq[i] * min(abs(i - (t - 1)), abs(i - (t + 1)))
        total_cost.append((t, cost))

    # Find the minimum cost and corresponding t
    min_cost = float('inf')
    best_t = 0
    for t, cost in total_cost:
        if cost < min_cost:
            min_cost = cost
            best_t = t

    print(best_t, min_cost)

