def solve_problem(n, k, a):
    target = sum(a)
    dp = [[0] * (target + 1) for _ in range(n + 1)]
    dp[0][0] = 1
    mod = 10**9 + 7

    for i in range(n):
        for j in range(target, -1, -1):
            dp[i + 1][j] = (dp[i + 1][j] + dp[i][j]) % mod
            if j - a[i] >= 0:
                dp[i + 1][j] = (dp[i + 1][j] + dp[i][j - a[i]]) % mod

    ways_to_sort = dp[n][target]

    if k == 0:
        return 1 if ways_to_sort else 0

    if n * (n - 1) // 2 < k:
        return 0

    ways_to_revert = pow(2, k, mod)
    for i in range(1, min(n, target) + 1):
        for j in range(target - i + 1):
            ways_to_revert = (ways_to_revert - comb(n, i) * comb(target, j) * comb(n - i, target - j) * pow(2, k - 1, mod) * mod_inverse(comb(n, i) * comb(target, j) * comb(n - i, target - j) % mod, mod) % mod) % mod

    return ways_to_sort * mod_inverse(ways_to_revert, mod) % mod

