    cnt_0, cnt_1 = a.count(0), a.count(1)
    if cnt_0 > cnt_1:
        a = [1 - x for x in a]
        cnt_0, cnt_1 = n - cnt_0, n - cnt_1
    def comb(n, r, mod=10**9+7):
        return (reduce(mul, (inv_fact[x] for x in range(r + 1, n + 1)), 1) * inv_fact[n - r]) % mod
    ans = 1
    for i in range(cnt_0, cnt_1 + 1):
        ans = (ans * comb(cnt_0, i) * comb(n - cnt_0, n - i - 1)) % (10**9+7)
