        return 1

    zeros = a.count(0)
    ones = n - zeros

    if zeros == 0 or ones == 0 or (zeros == 1 and ones == 1):
        return 0

    inv2 = modinv(2)

    # Calculate the number of swaps needed to sort the array
    swaps_needed = zeros * (n - zeros)

    if k < swaps_needed:
        return 0

