    dp[0][0] = 1
    for i in range(n):
        for j in range(i+1):
            if j == 0:
                dp[i+1][j] = (dp[i+1][j] + dp[i][j] * (intervals[i][0] - intervals[i][1] + 1)) % mod
            else:
                dp[i+1][j] = (dp[i+1][j] + dp[i][j] * (intervals[i][0] - max(intervals[i][1], intervals[i-1][1]) + 1)) % mod
                dp[i+1][j] = (dp[i+1][j] + dp[i][j-1] * (min(intervals[i][0], intervals[i-1][0]) - intervals[i-1][1] + 1)) % mod
    return dp[n][n-1]

